SELECT vehicle_id, signal_id
FROM vehicle_signal_values
WHERE anomaly_detected = 1;

SELECT vehicle_id, signal_id, MAX(timestamp) AS latest_timestamp
FROM vehicle_signal_values
GROUP BY vehicle_id, signal_id;

SELECT COUNT(*) AS unresolved_error_count
FROM vehicle_errors
WHERE vehicle_id = 0 AND resolved_status = 0;

SELECT description
FROM vehicle_errors
WHERE vehicle_id = 1;

SELECT COUNT(*) as alert_count
FROM vehicle_signal_values
WHERE vehicle_id = 0 AND signal_id = 1 AND alert_status = 1;

SELECT MAX(value) AS max_signal_value
FROM signal_values
WHERE vehicle_id = 1;
